patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..db23d13c20c2 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3149,6 +3149,40 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
       }
     }
   }
+  Value *C0, *C1;
+  if (match(CondVal, m_LogicalAnd(m_Value(C0), m_Value(C1))) && CondVal->hasOneUse()) {
+    if (SelectInst *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
+      if (FalseSI->hasOneUse()) {
+        if (FalseSI->getCondition() == C0) {
+          // select(C0 & C1, X, select(C0, Y, Z)) -> select(C0, select(C1, X, Y), Z)
+          Value *InnerSel = Builder.CreateSelect(C1, TrueVal, FalseSI->getTrueValue());
+          return replaceInstUsesWith(SI, Builder.CreateSelect(C0, InnerSel, FalseSI->getFalseValue()));
+        }
+        if (FalseSI->getCondition() == C1) {
+          // select(C0 & C1, X, select(C1, Y, Z)) -> select(C1, select(C0, X, Y), Z)
+          Value *InnerSel = Builder.CreateSelect(C0, TrueVal, FalseSI->getTrueValue());
+          return replaceInstUsesWith(SI, Builder.CreateSelect(C1, InnerSel, FalseSI->getFalseValue()));
+        }
+      }
+    }
+  }
+
+  if (match(CondVal, m_LogicalOr(m_Value(C0), m_Value(C1))) && CondVal->hasOneUse()) {
+    if (SelectInst *TrueSI = dyn_cast<SelectInst>(TrueVal)) {
+      if (TrueSI->hasOneUse()) {
+        if (TrueSI->getCondition() == C0) {
+          // select(C0 | C1, select(C0, X, Y), Z) -> select(C0, X, select(C1, Y, Z))
+          Value *InnerSel = Builder.CreateSelect(C1, TrueSI->getFalseValue(), FalseVal);
+          return replaceInstUsesWith(SI, Builder.CreateSelect(C0, TrueSI->getTrueValue(), InnerSel));
+        }
+        if (TrueSI->getCondition() == C1) {
+          // select(C0 | C1, select(C1, X, Y), Z) -> select(C1, X, select(C0, Y, Z))
+          Value *InnerSel = Builder.CreateSelect(C0, TrueSI->getFalseValue(), FalseVal);
+          return replaceInstUsesWith(SI, Builder.CreateSelect(C1, TrueSI->getTrueValue(), InnerSel));
+        }
+      }
+    }
+  }

   auto canMergeSelectThroughBinop = [](BinaryOperator *BO) {
     // The select might be preventing a division by 0.

